data.content:
Here are the MSTest comparison assertions you need and a complete test class:

**Key assertions for boundary checking:**

| Assertion | Purpose |
|-----------|---------|
| `Assert.IsGreaterThan(lowerBound, actual)` | Value exceeds a minimum |
| `Assert.IsLessThan(upperBound, actual)` | Value is below a maximum |
| `Assert.IsInRange(actual, low, high)` | Value falls within bounds |

**Example test class:**

```csharp
using Contoso.Scoring;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_IsInValidRange()
    {
        var result = _calculator.CalculatePercentage(3, 7);

        Assert.IsGreaterThan(0.0, result);
        Assert.IsLessThan(100.0, result);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_BelowMax_ReturnsValueInRange()
    {
        var result = _calculator.NormalizeScore(75.0, 150.0);

        Assert.IsGreaterThan(0.0, result);
        Assert.IsLessThan(100.0, result);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var result = _calculator.NormalizeScore(200.0, 100.0);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    [DataRow(95.0, "A")]
    [DataRow(90.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B")]
    [DataRow(70.0, "C")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    public void GetGrade_AtBoundaries_ReturnsCorrectGrade(double pct, string expected)
    {
        Assert.AreEqual(expected, _calculator.GetGrade(pct));
    }

    [TestMethod]
    public void CalculatePercentage_TotalIsZero_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }
}
```

**Summary of the comparison assertions:**
- `Assert.IsGreaterThan(lowerBound, actual)` — fails if `actual <= lowerBound`
- `Assert.IsLessThan(upperBound, actual)` — fails if `actual >= upperBound`
- `Assert.IsInRange(actual, low, high)` — fails if `actual` is outside `[low, high]`

These produce far better failure messages than `Assert.IsTrue(result > 0)` — on failure they show the actual value and the bound that was violated. Requires MSTest 3.x+.
